const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

export function quote(input: { customer: { yearsWithMHPCO: number; previousContract: boolean }; items: { type: string }[] }): number {
  if (input.items.length === 0) return PROCESSING_FEE;
  const basePremium = input.items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
  return basePremium + firstInsurance + PROCESSING_FEE;
}
